        return () => {
            setArcsData([]);
        };
    }, []); // Only re-run the effect if the page is remounted

    return (
        <Globe
            // ... other props here ...
            arcsData={arcsData} // Use the state for arcs data
            // ... rest of your props ...
        />
    );
