import Globe from 'react-globe.gl';
import * as THREE from 'three';
import { useRouter } from 'next/router';
import countries from './files/globe-data-min.json';
import travelHistory from './files/my-flights.json';
import airportHistory from './files/my-airports.json';

const GlobeComponent = () => {
    const [arcsData, setArcsData] = useState([]);
    const router = useRouter();
    const globeRef = useRef();

    useEffect(() => {
        // Check if the globe instance is loaded
        if (globeRef && globeRef.current) {
            // Access the Three.js scene
            const { scene } = globeRef.current;
            if (scene && scene.children.length > 0) {
                // Traverse the object tree to find the globe Mesh
                scene.traverse((object) => {
                    if (object instanceof THREE.Mesh && object.geometry instanceof THREE.SphereGeometry) {
                        // Assuming the globe is the only Mesh with a SphereGeometry

                        // Modify the material properties
                        object.material.color.set(0x3a228a);
                        object.material.emissive.set(0x220038);
                        object.material.emissiveIntensity = 0.1;
                        object.material.shininess = 0.7;

                        // If there are any changes to the texture or other properties, it's a good idea to
                        // update the WebGL rendering for those changes to take effect
                        object.material.needsUpdate = true;
                    }
                });
            }
        }
    }, []);


    useEffect(() => {
        const handleRouteChange = () => {
            // You could update state here to ensure fresh data is fetched when a route changes
            setArcsData(travelHistory.flights);
        };

        router.events.on('routeChangeComplete', handleRouteChange);

        // Fetch the initial data
        setArcsData(travelHistory.flights);

        return () => {
            router.events.off('routeChangeComplete', handleRouteChange);
        };
    }, [router.events]);

    return (
        <Globe
            ref={globeRef}
            hexPolygonsData = { countries.features }
            hexPolygonResolution = { 3}
            hexPolygonMargin = { 0.7}
            showAtmosphere = { true}
            atmosphereColor ="#ffffff"
            atmosphereAltitude = { 0.2}
            backgroundColor="rgba(0, 0, 0, 0)"      
            hexPolygonColor = {(e) => {
            return ["KEN", "CHN", "FRA", "ZAF", "JPN", "USA", "AUS", "CAN"].includes(e.properties.ISO_A3)
                ? "rgba(255, 255, 255, 1)"
            : "rgba(255, 255, 255, 0.5)";
            }}
            width={1000}
            height={1000}
            arcsData={arcsData}
            arcColor = {(e) => {
                return e.status ? "#9cff00" : "#ff2e97";
            }}
            arcAltitude = {(e) => {
                return e.arcAlt;
            }}
            arcStroke = {(e) => {
                return e.status ? 0.5 : 0.3;
            }}
            arcDashLength = { 0.9}
            arcDashGap = { 4}
            arcDashAnimateTime = { 1000}
            arcsTransitionDuration = { 1000}
            arcDashInitialGap = {(e) => e.order * 1}
            labelsData = { airportHistory.airports }
            labelColor = {() => "#ffffff"}
            labelDotOrientation = {(e) => {
                return e.text === "NGA" ? "top" : "right";
            }}
            labelDotRadius = { 0.35}
            labelSize = {(e) => e.size}
            labelText = {"city" }
            labelResolution = { 6}
            labelAltitude = { 0.01}
            pointsData = { airportHistory.airports }
            pointColor = {() => "#ffffff"}
            pointsMerge = { true}
            pointAltitude = { 0.07}
            pointRadius = { 0.10}
        />
    );
};

export default GlobeComponent;
